#include <stdio.h>
#define MOD 1000000007
int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        int n,K; scanf("%d %d",&n,&K);
        int a[105];
        for(int i=0;i<n;++i) scanf("%d",&a[i]);
        long long dp[1005]={0};
        dp[0]=1;
        for(int i=0;i<n;++i){
            int x=a[i];
            for(int s=K;s>=x;--s){
                dp[s]=(dp[s]+dp[s-x])%MOD;
            }
        }
        printf("%lld\n",dp[K]);
    }
    return 0;
}

